const AIRTABLE_TOKEN = process.env.AIRTABLE_TOKEN;
const CUSTOMER_BASE_URL = 'https://api.airtable.com/v0/appT9NVuu8MyFHFsj/tblHtfXkcsmWjk1aQ';
const CUSTOMERS_URL = 'https://api.airtable.com/v0/appT9NVuu8MyFHFsj/tblxs0QLftdL72IUV';

// Fetch all Customer Base records (id + email)
const allContacts = [];
let offset = null;
do {
  const url = CUSTOMER_BASE_URL + '?pageSize=100&fields%5B%5D=Email' + (offset ? '&offset=' + offset : '');
  const page = await this.helpers.httpRequest({ method: 'GET', url, headers: { 'Authorization': 'Bearer ' + AIRTABLE_TOKEN } });
  for (const rec of (page.records || [])) {
    if (rec.fields.Email) allContacts.push({ id: rec.id, email: rec.fields.Email.toLowerCase().trim() });
  }
  offset = page.offset;
} while (offset);

// Build email -> record IDs map
const emailToIds = {};
for (const c of allContacts) {
  if (!emailToIds[c.email]) emailToIds[c.email] = [];
  emailToIds[c.email].push(c.id);
}

// Fetch all Customers (id + email)
const allCustomers = [];
offset = null;
do {
  const url = CUSTOMERS_URL + '?pageSize=100&fields%5B%5D=Email' + (offset ? '&offset=' + offset : '');
  const page = await this.helpers.httpRequest({ method: 'GET', url, headers: { 'Authorization': 'Bearer ' + AIRTABLE_TOKEN } });
  for (const rec of (page.records || [])) {
    if (rec.fields.Email) allCustomers.push({ id: rec.id, email: rec.fields.Email.toLowerCase().trim() });
  }
  offset = page.offset;
} while (offset);

// Output one item per customer that has matching contacts
const results = [];
for (const customer of allCustomers) {
  const contactIds = emailToIds[customer.email];
  if (contactIds && contactIds.length > 0) {
    results.push({ json: { customerId: customer.id, contactIds } });
  }
}

return results;
